import{waitForAuth,getCurrentUser}from '../shared/guard-utils.js';(async function portalGuard(){const isLocalhost=['localhost','127.0.0.1',''].includes(window.location.hostname);if(isLocalhost){return;}try{await waitForAuth();await window.Auth.State.init();if(!window.Auth.State.isAuthenticated){const currentPath=window.location.pathname;const currentPage=currentPath.substring(currentPath.lastIndexOf('/')+1);if(currentPage==='login.html'){return;}const redirectParam=encodeURIComponent(currentPath+window.location.search);window.location.replace(`/portal/login.html?redirect=${redirectParam}`);return;}window.__PORTAL_USER__={id: window.Auth.State.user?.id,email: window.Auth.State.user?.email,profile: window.Auth.State.profile};window.addEventListener('auth:signout',()=>{window.location.replace('/portal/login.html');});}catch(error){}})();